1	package update
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"os"
7		"path/filepath"
8		"time"
9	)
10	
11	const (
12		cacheTTL      = 24 * time.Hour
13		errorRetryTTL = 5 * time.Minute
14		cacheFileName = "last-update-check.json"
15	)
16	
17	// Cache manages the update check cache file
18	type Cache struct {
19		filePath string
20		data     *CacheData
21	}
22	
23	// NewCache creates a new Cache instance
24	func NewCache() *Cache {
25		return &Cache{
26			data: &CacheData{},
27		}
28	}
29	
30	// Load reads cache from disk
31	func (c *Cache) Load() error {
32		// Get cache file path
33		if c.filePath == "" {
34			path, err := c.getCacheFilePath()
35			if err != nil {
36				return fmt.Errorf("failed to determine cache path: %w", err)
37			}
38			c.filePath = path
39		}
40	
41		// Read file
42		data, err := os.ReadFile(c.filePath)
43		if err != nil {
44			return err // Return raw error for os.IsNotExist check
45		}
46	
47		// Parse JSON
48		if err := json.Unmarshal(data, c.data); err != nil {
49			return fmt.Errorf("failed to parse cache: %w", err)
50		}
51	
52		return nil
53	}
54	
55	// Save writes cache to disk
56	func (c *Cache) Save() error {
57		// Get cache file path
58		if c.filePath == "" {
59			path, err := c.getCacheFilePath()
60			if err != nil {
61				return fmt.Errorf("failed to determine cache path: %w", err)
62			}
63			c.filePath = path
64		}
65	
66		// Ensure directory exists
67		dir := filepath.Dir(c.filePath)
68		if err := os.MkdirAll(dir, 0755); err != nil {
69			return fmt.Errorf("failed to create cache directory: %w", err)
70		}
71	
72		// Marshal to JSON
73		data, err := json.MarshalIndent(c.data, "", "  ")
74		if err != nil {
75			return fmt.Errorf("failed to marshal cache: %w", err)
76		}
77	
78		// Write to file
79		if err := os.WriteFile(c.filePath, data, 0644); err != nil {
80			return fmt.Errorf("failed to write cache: %w", err)
81		}
82	
83		return nil
84	}
85	
86	// IsExpired checks whether the cache should be refreshed.
87	// Successful checks use the long TTL; failed checks retry sooner to avoid dogpiling.
88	func (c *Cache) IsExpired() bool {
89		if c.data.LastCheck.IsZero() {
90			return true // No check recorded
91		}
92		ttl := cacheTTL
93		if c.data.CheckError != "" {
94			ttl = errorRetryTTL
95		}
96		return time.Since(c.data.LastCheck) > ttl
97	}
98	
99	// getCacheFilePath returns the cache file path following XDG Base Directory spec
100	func (c *Cache) getCacheFilePath() (string, error) {
101		// Check XDG_CACHE_HOME first
102		cacheDir := os.Getenv("XDG_CACHE_HOME")
103		if cacheDir == "" {
104			// Fall back to ~/.cache
105			homeDir, err := os.UserHomeDir()
106			if err != nil {
107				return "", fmt.Errorf("failed to get home directory: %w", err)
108			}
109			cacheDir = filepath.Join(homeDir, ".cache")
110		}
111	
112		return filepath.Join(cacheDir, "ddx", cacheFileName), nil
113	}
